class Solution(object):
    def maxPoints(self, technique1, technique2, k):
        n = len(technique1)
        # Start with all tasks using technique1
        total = sum(technique1)
        # Delta for switching task i from t1 to t2
        deltas = sorted([technique2[i] - technique1[i] for i in range(n)], reverse=True)
        # Apply the best (n-k) switches (only positive ones)
        for i in range(n - k):
            if deltas[i] > 0:
                total += deltas[i]
            else:
                break
        return total
